          (Xml.child xml_arg0 "NumTrueNegatives") in
      let numFalsePositives =
        (Option.map ~f:RecordsCount.of_xml)
          (Xml.child xml_arg0 "NumFalsePositives") in
      let numTruePositives =
        (Option.map ~f:RecordsCount.of_xml)
          (Xml.child xml_arg0 "NumTruePositives") in
      make ?numFalseNegatives ?numTrueNegatives ?numFalsePositives
        ?numTruePositives ()
