module StartingEventBatchCondition =
  struct
    type nonrec t =
      {
      batchSize: NullableInteger.t option
        [@ocaml.doc "Number of events in the batch."];
      batchWindow: NullableInteger.t option
        [@ocaml.doc "Duration of the batch window in seconds."]}
    let make ?batchSize =
      fun ?batchWindow -> fun () -> { batchSize; batchWindow }
    let to_value x =
      structure_to_value
        [("BatchSize", (Option.map x.batchSize ~f:NullableInteger.to_value));
        ("BatchWindow",
          (Option.map x.batchWindow ~f:NullableInteger.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let batchWindow =
        (Option.map ~f:NullableInteger.of_xml)
          (Xml.child xml_arg0 "BatchWindow") in
      let batchSize =
        (Option.map ~f:NullableInteger.of_xml)
          (Xml.child xml_arg0 "BatchSize") in
      make ?batchWindow ?batchSize ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json =
      let batchWindow = field_map json "BatchWindow" NullableInteger.of_json in
      let batchSize = field_map json "BatchSize" NullableInteger.of_json in
      make ?batchWindow ?batchSize ()
