        [("Name", (Option.map x.name ~f:NameString.to_value));
        ("TransformType",
          (Option.map x.transformType ~f:TransformType.to_value));
        ("Status", (Option.map x.status ~f:TransformStatusType.to_value));
        ("GlueVersion",
          (Option.map x.glueVersion ~f:GlueVersionString.to_value));
        ("CreatedBefore", (Option.map x.createdBefore ~f:Timestamp.to_value));
        ("CreatedAfter", (Option.map x.createdAfter ~f:Timestamp.to_value));
        ("LastModifiedBefore",
          (Option.map x.lastModifiedBefore ~f:Timestamp.to_value));
        ("LastModifiedAfter",
