      let glueVersion =
        (Option.map ~f:GlueVersionString.of_xml)
          (Xml.child xml_arg0 "GlueVersion") in
      let status =
        (Option.map ~f:TransformStatusType.of_xml)
          (Xml.child xml_arg0 "Status") in
      let transformType =
        (Option.map ~f:TransformType.of_xml)
